export default function Header () {
	return (
		<Box>
			<AppBar position='sticky'>

			{/* logo */}
			<Typography variant="h6" component="div" sx={{ flexGrow: 1, color: '#333' }}>Test</Typography>

			{/* navigation */}
			<Box sx={{ display: { xs: 'none', sm: 'block', backgroundColor: 'grey' } }}>
				<Button>Home</Button>
				<Button>About</Button>
				<Button>Contact</Button>
			</Box>

			</AppBar>
		</Box>
	)
}




